    return `<label class="et-album-select" title="추억 선택"><input type="checkbox" class="et-album-select-check" data-artifact-select="${escHtml(entry.id)}" ${selected.has(entry.id) ? 'checked' : ''}><span class="et-sr-only">선택</span></label>`;
