            roleSelectionCacheSize: turnEvidence.preAgentRoleSelections instanceof Map ? turnEvidence.preAgentRoleSelections.size : 0,
            roleSelectionReuseHits: Number(turnEvidence.preAgentRoleSelectionReuseHits || 0),
